class Solution:
    def countWays(self, nums: List[int]) -> int:
        nums.sort()
        n = len(nums)
        res = 0
        # Check for selecting 0 students
        if nums[0] > 0:
            res += 1
        # Check for selecting all students
        if nums[-1] < n:
            res += 1
        # Check for selecting k students where 1 <= k <= n-1
        for i in range(1, n):
            if nums[i - 1] < i and nums[i] > i:
                res += 1
        return res
